function createVenueCard(venue) {
    const isFav = favorites.includes(venue.id);
    return `
        <div class="venue-card" data-id="${venue.id}">
            <div class="venue-img">
                <img src="${venue.image}" alt="${venue.title}" style="width: 100%; height: 100%; object-fit: cover;">
                <button class="heart-btn ${isFav ? 'active' : ''}" data-fav-id="${venue.id}">
                    <svg viewBox="0 0 24 24"><path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z"/></svg>
                </button>
            </div>
            <div class="venue-info">
                <div class="venue-title">${venue.title}</div>
                <div class="venue-meta">
                    <svg width="12" height="12" fill="var(--primary)" viewBox="0 0 24 24"><path d="M12 17.27L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2 9.19 8.63 2 9.24l5.46 4.73L5.82 21z"/></svg>
                    <span>${venue.rating}</span> • <span>${venue.location}</span>
                </div>
            </div>
        </div>
    `;
}

function toggleFavorite(id, e) {
    e.stopPropagation();
    const index = favorites.indexOf(id);
    if (index > -1) {
        favorites.splice(index, 1);
    } else {
        favorites.push(id);
    }
    saveFavorites();

    // UI Feedback
    const btn = e.currentTarget;
    btn.classList.toggle('active');

    // If currently in favorites tab, re-render
    const activeNav = document.querySelector('.nav-item.active');
    if (activeNav && activeNav.getAttribute('data-target') === 'favorites') {
        renderFavorites();
    }
}

function renderContent(category = 'All') {
    const recommendedGrid = document.getElementById('recommended-grid');
    const exploreGrid = document.getElementById('explore-grid');
    const inProgressMessage = document.getElementById('in-progress-message');
    const homeSection = document.getElementById('home');
    const exploreSection = document.getElementById('explore');

    // Handle Location States dynamically
    // Check if the current city exists in the data (or "Locating...")
    let locationData = mockData;
    let cityHasData = true;

    // Special Case: Sahara category is Global
    const isSaharaGlobal = category === 'Sahara';

    if (currentLocation !== "Locating..." && !isSaharaGlobal) {
        locationData = mockData.filter(v => v.cityText === currentLocation);
        cityHasData = locationData.length > 0;
    } else if (isSaharaGlobal) {
        // Force all Sahara activities regardless of city
        locationData = mockData.filter(v => v.category === 'Sahara');
        cityHasData = true; // Always has data in this case
    }

    if (!cityHasData && currentLocation !== "Locating...") {
        if (homeSection) homeSection.style.display = 'none';
        if (exploreSection) exploreSection.style.display = 'none';
        if (inProgressMessage) {
            inProgressMessage.style.display = 'block';
            document.getElementById('target-city-name').textContent = currentLocation;
        }
        return;
    } else {
        // Restore sections, hide message
        if (inProgressMessage) inProgressMessage.style.display = 'none';
        if (homeSection) homeSection.style.display = '';
        if (exploreSection) exploreSection.style.display = '';
    }

    let filteredData = locationData; // Start with location-filtered data

    // 1. Text Search Filter
    if (searchQuery.trim() !== '') {
        const lowerQuery = searchQuery.toLowerCase();
        filteredData = filteredData.filter(v => v.title.toLowerCase().includes(lowerQuery));
    }

    // 2. Category Filter
    if (category !== 'All') {
        filteredData = filteredData.filter(v => v.category === category);
    }

    // 3. Alphabetic Sort
    filteredData.sort((a, b) => a.title.localeCompare(b.title));

    if (recommendedGrid) {
        // Show all filtered data instead of slicing so users see things
        recommendedGrid.innerHTML = filteredData.map(createVenueCard).join('');
    }

    if (exploreGrid) {
        exploreGrid.innerHTML = mockData.map(createVenueCard).join('');
    }

    attachCardListeners();
}

function showOfferDetails(id) {
    const offer = mockData.find(v => v.id === id);
    if (!offer) return;

    let dbEntry = null;
    if (typeof tarfihDB !== 'undefined' && tarfihDB.enterprises) {
        dbEntry = tarfihDB.enterprises.find(e => offer.provider.includes(e.providerId));
    }

    let extendedInfoHtml = '';
    if (dbEntry) {
        extendedInfoHtml = `
            <div class="offer-extended-info" style="margin-top:20px; background:var(--surface); padding:16px; border-radius:12px; font-size:14px; line-height:1.6;">
                <h4 style="margin-bottom:12px;">Provider Credentials & Contact</h4>
                <div><strong>Licence/Accreditation:</strong> ${dbEntry.credentials}</div>
                <div><strong>Address:</strong> ${dbEntry.address}</div>
                <div><strong>Phone:</strong> <a href="tel:${dbEntry.phone}" style="color:var(--primary);text-decoration:none;">${dbEntry.phone}</a></div>
                <div><strong>Email:</strong> <a href="mailto:${dbEntry.email}" style="color:var(--primary);text-decoration:none;">${dbEntry.email}</a></div>
                <div><strong>Website:</strong> <a href="${dbEntry.link}" target="_blank" style="color:var(--primary);text-decoration:none;">${dbEntry.link}</a></div>
                <div style="margin-top:8px;"><strong>Location GPS:</strong> ${dbEntry.localisation.lat}, ${dbEntry.localisation.lng}</div>
                ${dbEntry.reviewsCount ? `<div style="margin-top:8px;"><strong>Verified Reviews:</strong> ⭐️ ${offer.rating} (${dbEntry.reviewsCount} reviews)</div>` : ''}
            </div>
        `;
    }

    const content = document.getElementById('offer-content');
    content.innerHTML = `
        <img src="${offer.image}" alt="${offer.title}" class="offer-hero">
        <div class="offer-header">
            <h2 class="offer-title">${offer.title}</h2>
            <div class="offer-price">${offer.price}</div>
        </div>
        <div class="venue-meta" style="margin-bottom: 24px; font-size: 14px;">
            <svg width="14" height="14" fill="var(--primary)" viewBox="0 0 24 24"><path d="M12 17.27L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2 9.19 8.63 2 9.24l5.46 4.73L5.82 21z"/></svg>
            <span>${offer.rating} rating</span> • <span>${offer.location}</span>
        </div>

        <div class="offer-provider-card">
            <div class="provider-avatar">${offer.provider.charAt(0)}</div>
            <div class="provider-info">
                <h4>${offer.provider}</h4>
                <p>Verified Partner</p>
            </div>
        </div>
        
        ${extendedInfoHtml}

        <div class="offer-description" style="margin-top: 24px;">
            ${offer.description}
        </div>

        <button class="book-btn" onclick="openBookingModal(${offer.id})">Book Now</button>
    `;

    // Navigate to details section
    const sections = document.querySelectorAll('.section');
    sections.forEach(section => section.classList.remove('active'));
    document.getElementById('offer-details').classList.add('active');

    // Clear active nav
    document.querySelectorAll('.nav-item').forEach(i => i.classList.remove('active'));
    window.scrollTo({ top: 0, behavior: 'smooth' });
}

function attachCardListeners() {
    // 1. Details Click (Card Level)
    document.querySelectorAll('.venue-card').forEach(card => {
        card.addEventListener('click', (e) => {
            // IF clicking heart OR any of its children (SVG, path), STOP details flow
            if (e.target.closest('.heart-btn')) {
                return;
            }

            const id = parseInt(card.getAttribute('data-id'));
            showOfferDetails(id);
        });
    });

    // 2. Favorites Click (Heart Level)
    document.querySelectorAll('.heart-btn').forEach(btn => {
        btn.addEventListener('click', (e) => {
            e.stopPropagation(); // Stop bubbling
            e.preventDefault();  // Stop default button behavior
            const id = parseInt(btn.getAttribute('data-fav-id'));
            toggleFavorite(id, e);
        });
    });
}

function setupNavigation() {
    const navItems = document.querySelectorAll('.nav-item[data-target]');
    const sections = document.querySelectorAll('.section');

    navItems.forEach(item => {
        item.addEventListener('click', () => {
            const target = item.getAttribute('data-target');

            // Update Navigation UI
            navItems.forEach(i => i.classList.remove('active'));
            document.querySelectorAll(`.nav-item[data-target="${target}"]`).forEach(i => i.classList.add('active'));

            // Update Section visibility
            sections.forEach(section => {
                section.classList.remove('active');
                if (section.id === target) {
                    section.classList.add('active');
                }
            });

            // If target is favorites, render them
            if (target === 'favorites') {
                renderFavorites();
            }

            // If target is partners, render them
            if (target === 'partners') {
                renderPartners();
            }

            // Scroll to top
            window.scrollTo({ top: 0, behavior: 'smooth' });
        });
    });

    const backBtn = document.getElementById('back-button');
    if (backBtn) {
        backBtn.addEventListener('click', () => {
            // Restore home section
            document.querySelectorAll('.section').forEach(s => s.classList.remove('active'));
            document.getElementById('home').classList.add('active');

            // Restore Home nav active state
            document.querySelectorAll('.nav-item').forEach(i => i.classList.remove('active'));
            document.querySelectorAll('.nav-item[data-target="home"]').forEach(i => i.classList.add('active'));
        });
    }
}

function setupCategoryFilters() {
    const pills = document.querySelectorAll('.category-pill');
    pills.forEach(pill => {
        pill.addEventListener('click', () => {
            pills.forEach(p => p.classList.remove('active'));
            pill.classList.add('active');

            const category = pill.getAttribute('data-cat');
            renderContent(category);
        });
    });
}

function setupLocationSelector() {
    const locationSelect = document.getElementById('location-select');
    if (!locationSelect) return;

    locationSelect.addEventListener('change', async (e) => {
        const val = e.target.value;

        if (val === 'Current') {
            if ("geolocation" in navigator) {
                // Temporary state while fetching
                currentLocation = "Locating...";
                renderContent();

                navigator.geolocation.getCurrentPosition(async (position) => {
                    try {
                        const { latitude, longitude } = position.coords;
                        // Reverse Geocode using Nominatim
                        const res = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}`);
                        const data = await res.json();

                        let city = data.address.city || data.address.town || data.address.village || data.address.county || 'Unknown Location';
                        currentLocation = city;

                        // Add option dynamically if not exists, so it stays selected
                        let exists = Array.from(locationSelect.options).some(opt => opt.value === currentLocation);
                        if (!exists) {
                            const newOpt = document.createElement('option');
                            newOpt.value = currentLocation;
                            newOpt.textContent = currentLocation;
                            locationSelect.insertBefore(newOpt, locationSelect.options[locationSelect.options.length - 1]);
                        }

                        locationSelect.value = currentLocation;
                        renderContent();
                    } catch (error) {
                        console.error("Geocoding failed", error);
                        currentLocation = "Unknown Location";
                        renderContent();
                    }
                }, (error) => {
                    console.error("Geolocation error", error);
                    alert("Unable to retrieve location. Please check your browser permissions.");
                    locationSelect.value = 'Annaba';
                    currentLocation = 'Annaba';
                    renderContent();
                });
            } else {
                alert("Geolocation is not supported by this browser.");
                locationSelect.value = 'Annaba';
                currentLocation = 'Annaba';
                renderContent();
            }
        } else {
            currentLocation = val;
            renderContent();
        }
    });
}

// ===== AI SMART SEARCH ENGINE =====

const aiSynonyms = {
    // Category synonyms
    beach: 'Beaches', sea: 'Beaches', coast: 'Beaches', swim: 'Beaches', ocean: 'Beaches', surf: 'Beaches', jetski: 'Beaches', dive: 'Beaches', diving: 'Beaches', paddle: 'Beaches', kayak: 'Beaches', fishing: 'Beaches', boat: 'Beaches', snorkel: 'Beaches',
    hike: 'Hiking', hiking: 'Hiking', trek: 'Hiking', trekking: 'Hiking', mountain: 'Hiking', nature: 'Hiking', forest: 'Hiking', trail: 'Hiking', camp: 'Hiking', camping: 'Hiking', cave: 'Hiking', caving: 'Hiking', paraglide: 'Hiking', paragliding: 'Hiking', outdoor: 'Hiking',
    desert: 'Sahara', sahara: 'Sahara', sand: 'Sahara', dune: 'Sahara', camel: 'Sahara', oasis: 'Sahara', tuareg: 'Sahara', tassili: 'Sahara', stargazing: 'Sahara', balloon: 'Sahara', sandboard: 'Sahara',
    sport: 'Sport', hobby: 'Sport', bike: 'Sport', cycling: 'Sport', quad: 'Sport', archery: 'Sport', bowling: 'Sport', climb: 'Sport', climbing: 'Sport', horse: 'Sport', riding: 'Sport', buggy: 'Sport', adrenaline: 'Sport', extreme: 'Sport', thrill: 'Sport',
    history: 'Historical', historical: 'Historical', museum: 'Historical', ruin: 'Historical', ruins: 'Historical', roman: 'Historical', basilica: 'Historical', heritage: 'Historical', monument: 'Historical', lighthouse: 'Historical', ancient: 'Historical', old: 'Historical'
};

const priceKeywords = {
    free: { max: 0 },
    cheap: { max: 2000 },
    budget: { max: 3000 },
    affordable: { max: 3000 },
    moderate: { min: 2000, max: 6000 },
    expensive: { min: 5000 },
    premium: { min: 8000 },
    luxury: { min: 8000 }
};

const ratingKeywords = ['best', 'top', 'highest', 'rated', 'popular', 'recommended', 'amazing', 'excellent'];

function parseAIQuery(query) {
    const lower = query.toLowerCase().trim();
    const tokens = lower.split(/\s+/);
    const result = { categories: [], priceFilter: null, sortByRating: false, textSearch: [], isFamily: false, memberCount: null, rawQuery: query };

    // Extract family or kids keywords
    if (lower.match(/(?:family|kids|children|toddler|baby|babies)/)) {
        result.isFamily = true;
    }

    // Extract member count like "4 members", "3 people", "group of 5"
    const memberMatch = lower.match(/(\d+)\s*(?:members?|people|persons?|adults?|kids?|children)/);
    if (memberMatch) {
        result.memberCount = parseInt(memberMatch[1]);
        result.isFamily = true; // Broadly categorize groups seeking specific member counts as needing inclusive activities
    }

    // Extract price from "under XXXX" or "below XXXX" patterns
    const underMatch = lower.match(/(?:under|below|less than|max|up to)\s+(\d+)/);
    if (underMatch) {
        result.priceFilter = { max: parseInt(underMatch[1]) };
    }

    // Extract price from "over XXXX" or "above XXXX"
    const overMatch = lower.match(/(?:over|above|more than|min|at least)\s+(\d+)/);
    if (overMatch) {
        result.priceFilter = result.priceFilter || {};
        result.priceFilter.min = parseInt(overMatch[1]);
    }

    tokens.forEach(token => {
        // Check category synonyms
        if (aiSynonyms[token]) {
            if (!result.categories.includes(aiSynonyms[token])) {
                result.categories.push(aiSynonyms[token]);
            }
        }

        // Check price keywords
        if (priceKeywords[token]) {
            result.priceFilter = priceKeywords[token];
        }

        // Check rating keywords
        if (ratingKeywords.includes(token)) {
            result.sortByRating = true;
        }
    });

    // Remaining tokens for text matching (filter out matched tokens)
    const matchedTokens = new Set([
        ...Object.keys(aiSynonyms),
        ...Object.keys(priceKeywords),
        ...ratingKeywords,
        'under', 'below', 'less', 'than', 'max', 'up', 'to',
        'over', 'above', 'more', 'min', 'at', 'least', 'members', 'member', 'people', 'person', 'persons',
        'things', 'do', 'in', 'the', 'a', 'an', 'and', 'or', 'for', 'with', 'fun', 'activities', 'activity', 'experience', 'experiences', 'family', 'kids', 'children'
    ]);
    tokens.forEach(token => {
        if (!matchedTokens.has(token) && token.length > 2) {
            result.textSearch.push(token);
        }
    });

    return result;
}

function applyAISearch(data, parsed) {
    let results = [...data];

    // Category filter
    if (parsed.categories.length > 0) {
        results = results.filter(item => parsed.categories.includes(item.category));
    }

    // Price filter
    if (parsed.priceFilter) {
        results = results.filter(item => {
            const priceNum = parseInt(item.price.replace(/[^\d]/g, '')) || 0;
            const isFree = item.price.toLowerCase() === 'free';

            if (parsed.priceFilter.max === 0) return isFree;
            if (parsed.priceFilter.max && priceNum > parsed.priceFilter.max) return false;
            if (parsed.priceFilter.min && priceNum < parsed.priceFilter.min) return false;
            return true;
        });
    }

    // Family/Group filter: remove extreme activities not suitable for kids
    if (parsed.isFamily) {
        const extremeKeywords = ['skydiving', 'extreme', 'quad', 'adrenaline'];
        results = results.filter(item => {
            const searchable = (item.title + ' ' + item.description + ' ' + item.category).toLowerCase();
            // Optional: If you want to only show items that explicitly mention family, you could do that here.
            // For now, ensuring it filters out unsafe extreme sports is a good start.
            return !extremeKeywords.some(term => searchable.includes(term));
        });
    }

    // Text search (fuzzy title + description match)
    if (parsed.textSearch.length > 0) {
        results = results.filter(item => {
            const searchable = (item.title + ' ' + item.description + ' ' + item.provider).toLowerCase();
            return parsed.textSearch.some(token => searchable.includes(token));
        });
    }

    // Sort by rating if requested, otherwise alphabetic
    if (parsed.sortByRating) {
        results.sort((a, b) => parseFloat(b.rating) - parseFloat(a.rating));
    } else {
        results.sort((a, b) => a.title.localeCompare(b.title));
    }

    return results;
}

function buildSummaryHTML(parsed, resultCount) {
    const parts = [];

    if (parsed.categories.length > 0) {
        const cats = parsed.categories.map(c => `<span class="ai-keyword">${c}</span>`).join(' ');
        parts.push(`category ${cats}`);
    }

    if (parsed.priceFilter) {
        if (parsed.priceFilter.max === 0) {
            parts.push('<span class="ai-keyword">Free</span> only');
        } else if (parsed.priceFilter.max) {
            parts.push(`under <span class="ai-keyword">${parsed.priceFilter.max} DZD</span>`);
        }
        if (parsed.priceFilter.min) {
            parts.push(`above <span class="ai-keyword">${parsed.priceFilter.min} DZD</span>`);
        }
    }

    if (parsed.sortByRating) {
        parts.push('sorted by <span class="ai-keyword">★ rating</span>');
    }

    if (parsed.isFamily || parsed.memberCount) {
        const countTxt = parsed.memberCount ? `a ${parsed.memberCount}-member ` : '';
        parts.push(`suitable for <span class="ai-keyword">${countTxt}family</span>`);
    }

    const sparkle = `<span class="ai-summary-icon"><svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="#7C3AED" stroke-width="2"><path d="M12 2L15.09 8.26L22 9.27L17 14.14L18.18 21.02L12 17.77L5.82 21.02L7 14.14L2 9.27L8.91 8.26L12 2Z"/></svg></span>`;
    const filterInfo = parts.length > 0 ? ` — Filtering by ${parts.join(', ')}` : '';

    return `${sparkle} Found <strong>${resultCount}</strong> result${resultCount !== 1 ? 's' : ''}${filterInfo}`;
}

let aiSearchQuery = '';
let aiSearchDebounce = null;

function setupAISearch() {
    const input = document.getElementById('ai-search-input');
    const clearBtn = document.getElementById('ai-search-clear');
    const chipsContainer = document.getElementById('ai-search-chips');
    const summaryEl = document.getElementById('ai-search-summary');
    if (!input) return;

    function performSearch(query) {
        aiSearchQuery = query;
        clearBtn.style.display = query.length > 0 ? 'block' : 'none';

        // Update chip active states
        document.querySelectorAll('.ai-chip').forEach(chip => {
            chip.classList.toggle('active', chip.dataset.query === query);
        });

        // Find active category pill
        const activeCatPill = document.querySelector('.category-pill.active');
        const activeCat = activeCatPill ? activeCatPill.getAttribute('data-cat') : 'All';
        renderContent(activeCat);
    }

    // Input handler with debounce
    input.addEventListener('input', (e) => {
        clearTimeout(aiSearchDebounce);
        aiSearchDebounce = setTimeout(() => {
            performSearch(e.target.value);
        }, 250);
    });

    // Clear button
    clearBtn.addEventListener('click', () => {
        input.value = '';
        performSearch('');
        input.focus();
    });

    // Suggestion chips
    chipsContainer.addEventListener('click', (e) => {
        const chip = e.target.closest('.ai-chip');
        if (!chip) return;

        const query = chip.dataset.query;
        // Toggle: if already active, clear
        if (chip.classList.contains('active')) {
            input.value = '';
            performSearch('');
        } else {
            input.value = query;
            performSearch(query);
        }
    });

    // Keyboard shortcuts
    input.addEventListener('keydown', (e) => {
        if (e.key === 'Escape') {
            input.value = '';
            performSearch('');
            input.blur();
        }
    });
}

// ===== MODIFIED renderContent to use AI search =====

const _originalRenderContent = renderContent;

// Override renderContent
renderContent = function (category = 'All') {
    const recommendedGrid = document.getElementById('recommended-grid');
    const exploreGrid = document.getElementById('explore-grid');
    const inProgressMessage = document.getElementById('in-progress-message');
    const homeSection = document.getElementById('home');
    const exploreSection = document.getElementById('explore');
    const summaryEl = document.getElementById('ai-search-summary');

    // Handle Location States
    let locationData = mockData;
    let cityHasData = true;

    // Special Case: Sahara category is Global
    const isSaharaGlobal = category === 'Sahara';

    if (currentLocation !== "Locating..." && !isSaharaGlobal) {
        locationData = mockData.filter(v => v.cityText === currentLocation);
        cityHasData = locationData.length > 0;
    } else if (isSaharaGlobal) {
        // Force all Sahara activities regardless of city
        locationData = mockData.filter(v => v.category === 'Sahara');
        cityHasData = true; // Always has data for global Sahara
    }

    if (!cityHasData && currentLocation !== "Locating...") {
        if (homeSection) homeSection.style.display = 'none';
        if (exploreSection) exploreSection.style.display = 'none';
        if (inProgressMessage) {
            inProgressMessage.style.display = 'block';
            document.getElementById('target-city-name').textContent = currentLocation;
        }
        return;
    } else {
        if (inProgressMessage) inProgressMessage.style.display = 'none';
        if (homeSection) homeSection.style.display = '';
        if (exploreSection) exploreSection.style.display = '';
    }

    let filteredData = locationData;

    // Category filter
    if (category !== 'All' && !isSaharaGlobal) {
        filteredData = filteredData.filter(v => v.category === category);
    }

    // AI Search
    if (aiSearchQuery.trim() !== '') {
        const parsed = parseAIQuery(aiSearchQuery);
        filteredData = applyAISearch(filteredData, parsed);

        // Show summary
        if (summaryEl) {
            summaryEl.innerHTML = buildSummaryHTML(parsed, filteredData.length);
            summaryEl.style.display = 'flex';
        }
    } else {
        // No search — default alphabetic sort
        filteredData.sort((a, b) => a.title.localeCompare(b.title));
        if (summaryEl) summaryEl.style.display = 'none';
    }

    if (recommendedGrid) {
        recommendedGrid.innerHTML = filteredData.map(createVenueCard).join('');
    }

    if (exploreGrid) {
        exploreGrid.innerHTML = mockData.map(createVenueCard).join('');
    }

    attachCardListeners();
};

